// 現在言語のヘルプデータを返す（未翻訳idはja版にフォールバック）
function _getHelpData() {
    const lang = (typeof getLang === 'function') ? getLang() : 'ja';
    const tr = _HELP_I18N[lang];
    if (!tr) return _HELP_DATA;
    return _HELP_DATA.map(entry => {
        const t = tr[entry.id];
        if (!t) return entry;
        return { ...entry, label: t.label, sections: t.sections };
    });
}

// ヘルプの表示順（アプリのタブ順）。付録は末尾
const _HELP_ORDER = [
    'about',
    'page-work', 'page-template', 'page-export',
    'layout', 'image-tab', 'assetpanel',
    'font', 'wfmgallery', 'nanobanana', 'project', 'settings',
    'appendix-svg-template', 'appendix-balloon', 'appendix-inkscape-template', 'appendix-inkscape-balloon',
];

function _helpSorted() {
    const idx = id => {
        const i = _HELP_ORDER.indexOf(id);
        return i === -1 ? 999 : i;
    };
    return [..._getHelpData()].sort((a, b) => idx(a.id) - idx(b.id));
}

let _helpInitialized = false;
let _helpCurrentId = null;

function initHelpTab() {
    if (!_helpInitialized) {
        _helpInitialized = true;
        _helpBuildNav();

        const searchInput = document.getElementById('help-search');
        if (searchInput) {
            searchInput.addEventListener('input', () => {
                _helpFilterNav(searchInput.value.trim());
            });
        }
    }
    // 初期選択
    if (!_helpCurrentId) {
        const first = _helpSorted()[0];
        if (first) _helpShowItem(first.id);
    }
}

// ナビ: タブ順のフラットリスト（workflow studio のヘルプ形式）。付録は区切り見出し付きで末尾
function _helpBuildNav() {
    const nav = document.getElementById('help-nav');
    if (!nav) return;
    nav.innerHTML = '';

    let appendixDivided = false;
    _helpSorted().forEach(item => {
        if (item.group === 'appendix' && !appendixDivided) {
            appendixDivided = true;
            const divider = document.createElement('div');
            divider.className = 'help-nav-divider';
            divider.textContent = t('help.appendixDivider');
            nav.appendChild(divider);
        }
        const btn = document.createElement('button');
        btn.type = 'button';
        btn.className = 'help-nav-item';
        btn.dataset.helpId = item.id;
        btn.textContent = item.label;
        btn.addEventListener('click', () => _helpShowItem(item.id));
        nav.appendChild(btn);
    });
}

function _helpFilterNav(query) {
    const q = query.toLowerCase();
    const nav = document.getElementById('help-nav');
    if (!nav) return;

    nav.querySelectorAll('.help-nav-item').forEach(el => {
        const item = _getHelpData().find(d => d.id === el.dataset.helpId);
        if (!item) return;
        const match = !q
            || item.label.toLowerCase().includes(q)
            || item.kana.includes(q)
            || item.sections.some(s => s.body.toLowerCase().includes(q) || s.heading.toLowerCase().includes(q));
        el.style.display = match ? '' : 'none';
    });

    // 付録の区切り見出しは、いずれかの付録項目が可視のときのみ表示
    const divider = nav.querySelector('.help-nav-divider');
    if (divider) {
        const anyAppendix = _getHelpData().some(d => d.group === 'appendix'
            && nav.querySelector(`.help-nav-item[data-help-id="${d.id}"]`)?.style.display !== 'none');
        divider.style.display = anyAppendix ? '' : 'none';
    }
}

function _helpShowItem(id) {
    const item = _getHelpData().find(d => d.id === id);
    if (!item) return;
    _helpCurrentId = id;

    // ナビのアクティブ状態
    document.querySelectorAll('.help-nav-item').forEach(li => {
        li.classList.toggle('active', li.dataset.helpId === id);
    });

    const main = document.getElementById('help-main');
    if (!main) return;

    // セクションをカード形式で表示（workflow studio のヘルプ形式）
    const sectionsHtml = item.sections.map(s => `
        <div class="help-card">
            <h3 class="help-card-heading">${_escHtml(s.heading)}</h3>
            <div class="help-card-body">${s.body}</div>
        </div>
    `).join('');

    main.innerHTML = `
        <div class="help-article">
            <div class="help-article-header">
                <h2 class="help-article-title">${_escHtml(item.label)}</h2>
                <button class="btn small secondary help-jump-btn" data-tab="${_escHtml(item.tab)}">${t('help.jumpToTab')}</button>
            </div>
            ${sectionsHtml}
        </div>
    `;

    main.querySelector('.help-jump-btn')?.addEventListener('click', e => {
        switchTab(e.target.dataset.tab);
    });

    main.scrollTop = 0;
}

